// Stage 1: Fast keyword-based pre-screen
// Catches obvious violations before using Ollama

const body = $input.first().json.body || $input.first().json;
const content = (body.content || '').toLowerCase();
const productName = (body.product_name || '').toLowerCase();
const contentType = body.content_type || 'general';
const brandId = body.brand_id || 'clearstack';

// ── HARD BLOCKED — Auto-reject, never publish ──────────
const hardBlocked = [
  // Financial haram
  'interest rate', 'riba', 'loan with interest', 'credit card interest',
  'payday loan', 'forex trading tips', 'crypto get rich', 'gambling',
  'lottery', 'casino', 'betting', 'sports betting', 'stock tips',
  // Content haram  
  'alcohol', 'wine', 'beer', 'spirits', 'cocktail', 'whiskey',
  'pork', 'bacon', 'ham', 'lard',
  'adult content', 'nsfw', 'explicit', 'sexual', 'nude', 'erotic',
  'dating app', 'tinder', 'hookup',
  'halloween occult', 'witchcraft', 'black magic', 'voodoo', 'ouija',
  'violence', 'gore', 'weapon promotion',
  'drug', 'weed', 'cannabis promotion', 'nicotine promotion',
  'astrology reading', 'horoscope business', 'tarot'
];

// ── SOFT FLAGS — Need AI review before decision ─────────
const softFlags = [
  'music', 'concert', 'playlist', 'party planning',
  'valentine', 'romance', 'dating', 'relationship advice',
  'fashion model', 'lingerie',
  'investment', 'stock market', 'crypto', 'nft',
  'insurance', 'mortgage',
  'halloween', 'christmas secular',
  'yoga', 'meditation music',
  'wine tasting template', 'bar menu'
];

// ── ALWAYS PERMITTED — Fast pass ───────────────────────
const alwaysPermitted = [
  'productivity', 'planner', 'organization', 'business plan',
  'budget', 'savings', 'halal', 'islamic finance', 'zakah',
  'education', 'learning', 'study', 'notes',
  'printable', 'template', 'notion', 'canva',
  'wellness', 'self care', 'mindfulness', 'gratitude',
  'goal setting', 'habit tracker', 'journaling',
  'resume', 'cv', 'invoice', 'proposal',
  'social media', 'content calendar', 'marketing'
];

// Run checks
const hardBlockFound = hardBlocked.filter(term => content.includes(term) || productName.includes(term));
const softFlagFound = softFlags.filter(term => content.includes(term) || productName.includes(term));
const permittedFound = alwaysPermitted.filter(term => content.includes(term) || productName.includes(term));

let preScreenResult = 'NEEDS_AI_REVIEW';
let autoDecision = null;

if (hardBlockFound.length > 0) {
  preScreenResult = 'HARD_BLOCKED';
  autoDecision = 'REJECTED';
} else if (permittedFound.length > 0 && softFlagFound.length === 0) {
  preScreenResult = 'FAST_PASS';
  autoDecision = 'APPROVED';
} else {
  preScreenResult = 'NEEDS_AI_REVIEW';
  autoDecision = null;
}

return [{ json: {
  ...body,
  pre_screen: {
    result: preScreenResult,
    auto_decision: autoDecision,
    hard_blocks_found: hardBlockFound,
    soft_flags_found: softFlagFound,
    permitted_terms_found: permittedFound,
    needs_ai_review: preScreenResult === 'NEEDS_AI_REVIEW'
  }
}}];

// INSTANT REJECT — hard blocked content
const data = $input.first().json;
return [{ json: {
  approved: false,
  verdict: 'REJECTED',
  verdict_source: 'keyword_prescreen',
  reason: `Hard-blocked haram terms found: ${data.pre_screen.hard_blocks_found.join(', ')}`,
  flags: data.pre_screen.hard_blocks_found,
  cleaned_content: null,
  action_required: 'DISCARD — Do not publish this product',
  original_content: data.content,
  product_name: data.product_name,
  screened_at: new Date().toISOString()
}}];

// INSTANT APPROVE — clearly halal content
const data = $input.first().json;
return [{ json: {
  approved: true,
  verdict: 'APPROVED',
  verdict_source: 'keyword_prescreen',
  reason: 'Content passed halal pre-screen. No flags found.',
  flags: [],
  cleaned_content: data.content,
  action_required: null,
  original_content: data.content,
  product_name: data.product_name,
  screened_at: new Date().toISOString()
}}];

