// Parse mistral halal review
const raw = $input.first().json;
const inputData = $('🔀 Route by Pre-Screen Result').first().json;

let review;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  review = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  // If parsing fails, flag for human review to be safe
  review = {
    verdict: 'NEEDS_HUMAN_REVIEW',
    confidence: 'low',
    is_halal: false,
    issues_found: [{ issue: 'AI review parse error — human review required', severity: 'moderate' }],
    cleaned_content: inputData.content,
    flag_for_human: true,
    reviewer_note: 'Could not parse AI review response. Manual review required.'
  };
}

// Map verdict to approved boolean
const approved = review.verdict === 'APPROVED';
const needsHuman = review.verdict === 'NEEDS_HUMAN_REVIEW' || review.flag_for_human;

return [{ json: {
  approved: approved,
  needs_human_review: needsHuman,
  verdict: review.verdict,
  verdict_source: 'ollama_mistral',
  confidence: review.confidence,
  reason: review.reviewer_note,
  flags: (review.issues_found || []).map(i => i.issue),
  issues_detail: review.issues_found || [],
  suggested_edits: review.suggested_edits || [],
  cleaned_content: review.cleaned_content || inputData.content,
  flag_for_human: needsHuman,
  action_required: needsHuman ? 'MANUAL_REVIEW_REQUIRED — Check Halal_Review sheet' : null,
  original_content: inputData.content,
  product_name: inputData.product_name,
  pre_screen: inputData.pre_screen,
  screened_at: new Date().toISOString()
}}];

// Merge all three paths (blocked, approved, ai-reviewed) into single output
const allInputs = $input.all();
const result = allInputs[0]?.json;

// Add final metadata
return [{ json: {
  ...result,
  halal_check_complete: true,
  checked_at: new Date().toISOString()
}}];
